166	module FP17_ADD_mgc_shift_bl_v4(a,s,z);
167	   parameter    width_a = 4;
168	   parameter    signd_a = 1;
169	   parameter    width_s = 2;
170	   parameter    width_z = 8;
171	
172	   input [width_a-1:0] a;
173	   input [width_s-1:0] s;
174	   output [width_z -1:0] z;
175	
176	   generate if ( signd_a )
177	   begin: SIGNED
178	     assign z = fshl_s(a,s,a[width_a-1]);
179	   end
180	   else
181	   begin: UNSIGNED
182	     assign z = fshl_s(a,s,1'b0);
183	   end
184	   endgenerate
185	
186	   //Shift-left - unsigned shift argument one bit more
187	   function [width_z-1:0] fshl_u_1;
188	      input [width_a  :0] arg1;
189	      input [width_s-1:0] arg2;
190	      input sbit;
191	      parameter olen = width_z;
192	      parameter ilen = width_a+1;
193	      parameter len = (ilen >= olen) ? ilen : olen;
194	      reg [len-1:0] result;
195	      reg [len-1:0] result_t;
196	      begin
197	        result_t = {(len){sbit}};
198	        result_t[ilen-1:0] = arg1;
199	        result = result_t <<< arg2;
200	        fshl_u_1 =  result[olen-1:0];
201	      end
202	   endfunction // fshl_u
203	
204	   //Shift-left - unsigned shift argument
205	   function [width_z-1:0] fshl_u;
206	      input [width_a-1:0] arg1;
207	      input [width_s-1:0] arg2;
208	      input sbit;
209	      fshl_u = fshl_u_1({sbit,arg1} ,arg2, sbit);
210	   endfunction // fshl_u
211	
212	   //Shift right - unsigned shift argument
213	   function [width_z-1:0] fshr_u;
214	      input [width_a-1:0] arg1;
215	      input [width_s-1:0] arg2;
216	      input sbit;
217	      parameter olen = width_z;
218	      parameter ilen = signd_a ? width_a : width_a+1;
219	      parameter len = (ilen >= olen) ? ilen : olen;
220	      reg signed [len-1:0] result;
221	      reg signed [len-1:0] result_t;
222	      begin
223	        result_t = $signed( {(len){sbit}} );
224	        result_t[width_a-1:0] = arg1;
225	        result = result_t >>> arg2;
226	        fshr_u =  result[olen-1:0];
227	      end
228	   endfunction // fshl_u
229	
230	   //Shift left - signed shift argument
231	   function [width_z-1:0] fshl_s;
232	      input [width_a-1:0] arg1;
233	      input [width_s-1:0] arg2;
234	      input sbit;
235	      reg [width_a:0] sbit_arg1;
236	      begin
237	        // Ignoring the possibility that arg2[width_s-1] could be X
238	        // because of customer complaints regarding X'es in simulation results
239	        if ( arg2[width_s-1] == 1'b0 )
240	        begin
241	          sbit_arg1[width_a:0] = {(width_a+1){1'b0}};
242	          fshl_s = fshl_u(arg1, arg2, sbit);
243	        end
244	        else
245	        begin
246	          sbit_arg1[width_a] = sbit;
247	          sbit_arg1[width_a-1:0] = arg1;
248	          fshl_s = fshr_u(sbit_arg1[width_a:1], ~arg2, sbit);
249	        end
250	      end
251	   endfunction
252	
253	endmodule
