217	// This is to shorten the width of mant with fixed value
218	// RNE: Rounding to Nearest Even
219	template<unsigned int iMantWidth, unsigned int oMantWidth >
220	bool FpMantRNE (
221	     ACINTF(iMantWidth) i_data
222	    ,ACINTF(oMantWidth)& o_data
223	    ) {
224	    
225	    //====================================================
226	    const unsigned int TruncWidth = iMantWidth-oMantWidth;
227	    const unsigned int StickWidth = iMantWidth-oMantWidth-1;
228	    
229	    typedef ACINTF(TruncWidth) TruncType;
230	    typedef ACINTF(StickWidth) StickType;
231	    typedef ACINTF(1)          GuardType;
232	    typedef ACINTF(1)          CarryType;
233	    //
234	    typedef ACINTF(iMantWidth) iDataType;
235	    typedef ACINTF(oMantWidth) oDataType;
236	
237	    bool overflow = false;
238	    #pragma CTC SKIP
239	    if (iMantWidth <= oMantWidth) {
240	        o_data = ((oDataType)(i_data)) << (oMantWidth - iMantWidth);
241	        overflow = false;
242	    #pragma CTC ENDSKIP
243	    } else {
244	        // Exmaple: original 5 bits, need keep 2 MSB bits
245	        // L: LSB; G: GUARD; S:STICK; T: TRUNC
246	        // x  x  x  x  x 
247	        //   [L][G][ S  ] 
248	        //      [   T   ]
249	
250	
251	        TruncType t_mant = i_data.template slc<TruncWidth>(0);
252	        StickType s_mant = i_data.template slc<StickWidth>(0);
253	        GuardType g_mant = i_data.template slc<1>(StickWidth);
254	        oDataType o_mant = i_data.template slc<oMantWidth>(TruncWidth);
255	        #ifdef SVDEBUG    
256	        printf("\n RNE:i_data  = %x",i_data);
257	        printf("\n RNE:t_mant  = %x",t_mant);
258	        printf("\n RNE:s_mant  = %x",s_mant);
259	        printf("\n RNE:g_mant  = %x",g_mant);
260	        printf("\n RNE:o_mant  = %x",o_mant);
261	        #endif
262	        
263	        ACINTF(1) stick = s_mant.or_reduce();
264	        ACINTF(1) guard = g_mant==1;
265	        ACINTF(1) lsb   = o_mant[0]==1;
266	        CarryType carry = guard & (stick | lsb);
267	        #ifdef SVDEBUG    
268	        printf("\n RNE:stick  = %x",stick);
269	        printf("\n RNE:guard  = %x",guard);
270	        printf("\n RNE:lsb  = %x",lsb);
271	        printf("\n RNE:carry  = %x",carry);
272	        #endif
273	
274	        o_data = o_mant + (oDataType)carry;
275	        
276	        overflow = (carry & o_mant.and_reduce()) ? true : false;
277	
278	    }
279	
280	    return overflow;
281	}
