302	    typedef ACINTF(iMantWidth+1)  iMantPlusOneType;
303	    typedef ACINTF(oMantWidth)    oMantType;
304	    typedef ACINTF(oMantWidth+1)  oMantPlusOneType;
305	        
306	    iMantPlusOneType  i_mant_p1; i_mant_p1 = i_mant;
307	    i_mant_p1[iMantWidth] = 1; // add the implied 1
308	
309	    iMantPlusOneType guard_mask = ((iMantPlusOneType)1)<<(DeltaWidth+shift-1);
310	    iMantPlusOneType stick_mask = (((iMantPlusOneType)1)<<(DeltaWidth+shift-1)) - 1;
311	    iMantPlusOneType least_mask = ((iMantPlusOneType)1)<<(DeltaWidth+shift);
312	
313	    iMantPlusOneType guard_bits = i_mant_p1 & guard_mask; 
314	    iMantPlusOneType stick_bits = i_mant_p1 & stick_mask; 
315	    iMantPlusOneType least_bits = i_mant_p1 & least_mask; 
316	
317	    ACINTF(1) guard = guard_bits.or_reduce();
318	    ACINTF(1) stick = stick_bits.or_reduce();
319	    ACINTF(1) least = least_bits.or_reduce();
320	
321	    ACINTF(1) carry = guard & (stick | least);
322	
323	    iMantPlusOneType i_mant_s = i_mant_p1 >> shift;
324	    oMantPlusOneType o_mant_p1 = i_mant_s.template slc<11>(DeltaWidth);
325	
326	    oMantPlusOneType o_mant_sum = o_mant_p1 + carry;
327	
328	    o_mant = o_mant_sum.template slc<oMantWidth>(0);
329	    bool overflow = o_mant_sum[oMantWidth];
330	    
331	    return overflow;
332	}
