337	// in dla, this function will never used in Denorm Mode
338	template<unsigned int ExpoWidth, unsigned int iMantWidth, unsigned int oMantWidth, unsigned int DENORM, unsigned int NANMODE >
339	ACINTT(1+ExpoWidth+oMantWidth) FpMantWidthDec (
340	    ACINTT(1+ExpoWidth+iMantWidth) bits
341	    ) {
342	
343	    #pragma CTC SKIP
344	    assert (iMantWidth > oMantWidth);
345	    #pragma CTC ENDSKIP
346		
347	    enum { kExpoMax  = (1ull << ExpoWidth) - 1 };
348	
349	    // Exmaple: original 5 bits, need keep 2 MSB bits
350	    // L: LSB; G: GUARD; S:STICK; T: TRUNC
351	    // x  x  x  x  x 
352	    //   [L][G][ S  ] 
353	    //      [   T   ]
354	    const unsigned int TruncWidth = iMantWidth-oMantWidth;
355	    const unsigned int StickWidth = iMantWidth-oMantWidth-1;
356	
357	    typedef ACINTF(1+ExpoWidth+iMantWidth) uT;
358	    
359	    typedef ACINTF(1) SignType;
360	    typedef ACINTF(iMantWidth) iMantType;
361	    typedef ACINTF(iMantWidth+1) iMantPlusOneType;
362	    typedef ACINTF(oMantWidth) oMantType;
363	    typedef ACINTF(1+oMantWidth) oMantPlusOneType;
364	    typedef ACINTF(2+oMantWidth) oMantPlusTwoType;
365	    typedef ACINTF(ExpoWidth)  ExpoType;
366	
367	    typedef ACINTF(TruncWidth) TruncType;
368	    typedef ACINTF(StickWidth) StickType;
369	    typedef ACINTF(1)          GuardType;
370	    typedef ACINTF(1)          CarryType;
371	    
372	    iMantType i_mant;
373	    oMantType o_mant;
374	    
375	    ExpoType  i_expo;
376	    SignType  i_sign;
377	    
378	    SignType  o_sign;
379	
380	    FpSignedBitsToFloat<ExpoWidth,iMantWidth>(bits,i_sign,i_expo,i_mant);
381	
382	    o_sign = i_sign;
383	
384	    // + implied 1
385	    iMantPlusOneType i_mant_p1; i_mant_p1 = i_mant;
386	    i_mant_p1[iMantWidth] = 1; // add implied 1 on msb
387	
388	    #pragma CTC SKIP
389	    if (DENORM == DENORM_YES) {
390	        bool is_denorm = IsDenorm<ExpoWidth,iMantWidth>(i_expo,i_mant);
391	        if (is_denorm) {
392	            i_mant_p1[iMantWidth] = 0; // add implied 0 on msb
393	        }
394	    }
395	    #pragma CTC ENDSKIP
396	    
397	    oMantPlusOneType o_mant_p1;
398	    bool overflow = FpMantRNE<iMantWidth+1,oMantWidth+1>(i_mant_p1,o_mant_p1);
399	    o_mant = (oMantType)o_mant_p1;
400	
401	    ExpoType  o_expo; o_expo=i_expo;
402	    if (overflow) { // a denorm can never overflow 
403	        o_expo++;
404	        if (o_expo==kExpoMax) {
405	            SetToInf<ExpoWidth,oMantWidth>(o_sign,o_expo,o_mant);
406	        }
407	    } else {
408	        #pragma CTC SKIP
409	        if (DENORM == DENORM_YES) {
410	            bool is_denorm = IsDenorm<ExpoWidth,iMantWidth>(i_expo,i_mant);
411	            if (is_denorm && (o_mant_p1[oMantWidth] == 1)) {
412	                o_expo = 1; // a denorm becomes a norm after rounding
413	            }
414	        }
415	        #pragma CTC ENDSKIP
416	    }
417	    
418	    // NAN propagation
419	    #pragma CTC SKIP
420	    if (NANMODE == NAN_YES) {
421	        bool is_nan = IsNaN<ExpoWidth,iMantWidth>(i_expo,i_mant);
422	        if (is_nan) {
423	            o_sign = i_sign;
424	            o_expo = i_expo;
425	            o_mant = i_mant;
426	        }
427	    }
428	    #pragma CTC ENDSKIP
429	
430	    return FpFloatToSignedBits<ExpoWidth,oMantWidth>(o_sign,o_expo,o_mant);
431	}
