437	template<unsigned int iExpoWidth, unsigned int oExpoWidth, unsigned int MantWidth, unsigned int DENORM, unsigned int NANMODE >
438	ACINTT(1+oExpoWidth+MantWidth) FpExpoWidthInc (
439	    ACINTT(1+iExpoWidth+MantWidth) bits
440	    ) {
441	
442	    #pragma CTC SKIP
443	    assert (iExpoWidth <= oExpoWidth);
444	    #pragma CTC ENDSKIP
445	    
446	    const unsigned int koExpoBias = (1ull<< oExpoWidth)/2 - 1;
447	    const unsigned int kiExpoBias = (1ull<< iExpoWidth)/2 - 1;
448	    const unsigned int kExpoBiasDelta = koExpoBias - kiExpoBias;
449	    
450	    //const unsigned int kiExpoMax = (1ull << iExpoWidth) - 1 ;
451	    const unsigned int koExpoMax = (1ull << oExpoWidth) - 1 ;
452	    
453	    typedef ACINTF(1)          SignType;
454	    typedef ACINTF(iExpoWidth) iExpoType;
455	    typedef ACINTF(oExpoWidth) oExpoType;
456	    
457	    typedef ACINTF(MantWidth) MantType;
458	    typedef ACINTF(MantWidth+1) MantPlusOneType;
459	
460	    SignType  i_sign;
461	    iExpoType i_expo;
462	    MantType i_mant;
463	    
464	    SignType  o_sign;
465	    oExpoType o_expo;
466	    MantType o_mant;
467	    MantPlusOneType o_mant_p1;
468	    //const unsigned int ShiftWidth = oExpoWidth - iExpoWidth;
469	    FpSignedBitsToFloat<iExpoWidth,MantWidth>(bits,i_sign,i_expo,i_mant);
470	    
471	    o_sign = i_sign;
472	    o_mant = (MantType)(i_mant);
473	
474	    if (IsZero<iExpoWidth,MantWidth>(i_expo,i_mant)) {
475	        SetToZero<oExpoWidth,MantWidth>(o_sign,o_expo,o_mant);
476	    } else {
477	        o_expo = (oExpoType)(i_expo + kExpoBiasDelta);
478	    }
479	
480	    if (DENORM == DENORM_YES) {
481	        bool is_denorm = IsDenorm<iExpoWidth,MantWidth>(i_expo,i_mant);
482	        if (is_denorm) {
483	            // convert a denorm to a norm who has large expo width
484	            MantType zero_count = IntLeadZero<MantWidth>(i_mant);
485	            o_expo = kExpoBiasDelta - zero_count;
486	            o_mant = ((MantPlusOneType)i_mant)<<(zero_count+1); // add MSB, shift, and cut MSB
487	        }
488	    }
489	
490	    // INF based on the increased one
491	    if (IsInf<iExpoWidth,MantWidth>(i_expo,i_mant)) {
492	        SetToInf<oExpoWidth,MantWidth>(o_sign,o_expo,o_mant);
493	    }
494	    
495	    // NAN propagation
496	    //if (NANMODE == NAN_YES) {
497	        bool is_nan = IsNaN<iExpoWidth,MantWidth>(i_expo,i_mant);
498	        if (is_nan) {
499	            o_sign = i_sign;
500	            o_expo = koExpoMax;
501	            o_mant = i_mant;
502	        }
503	    //}
504	
505	    return FpFloatToSignedBits<oExpoWidth,MantWidth>(o_sign,o_expo,o_mant);
506	}
