598	// 1, if >max, or <min, set to INF | 0
599	// 2, if result is denorm, right shift mant with NRE
600	// 3, if result is norm, change expo accordingly
601	template<unsigned int iExpoWidth, unsigned int oExpoWidth, unsigned int MantWidth, unsigned int DENORM, unsigned int NANMODE >
602	ACINTT(1+oExpoWidth+MantWidth) FpExpoWidthDec (
603	    ACINTT(1+iExpoWidth+MantWidth) bits
604	    ) {
605	    
606	    #pragma CTC SKIP
607	    assert (iExpoWidth > oExpoWidth);
608	    #pragma CTC ENDSKIP
609	    
610	    const unsigned int koExpoMax = (1ull << oExpoWidth) - 1 ;
611	    //const unsigned int kiExpoMax = (1ull << iExpoWidth) - 1 ;
612	    const unsigned int koExpoBias = (1ull<< oExpoWidth)/2 - 1;
613	    const unsigned int kiExpoBias = (1ull<< iExpoWidth)/2 - 1;
614	    const unsigned int kExpoBiasDelta = kiExpoBias - koExpoBias;
615	
616	    typedef ACINTF(1)          SignType;
617	    typedef ACINTF(iExpoWidth) iExpoType;
618	    typedef ACINTF(oExpoWidth) oExpoType;
619	    typedef ACINTF(MantWidth)  MantType;
620	    typedef ACINTF(MantWidth+1)  MantPlusOneType;
621	
622	    SignType  i_sign;
623	    iExpoType i_expo;
624	    MantType  i_mant;
625	    
626	    FpSignedBitsToFloat<iExpoWidth,MantWidth>(bits,i_sign,i_expo,i_mant);
627	    
628	    SignType  o_sign; o_sign=i_sign;
629	    oExpoType o_expo;
630	    MantType  o_mant;
631	    
632	    if (i_expo >= koExpoMax + kExpoBiasDelta ) { // set to INF if greater than koExpoMax
633	        SetToInf<oExpoWidth,MantWidth>(o_sign,o_expo,o_mant);
634	    } else if (i_expo < kExpoBiasDelta - MantWidth) { // 0, small enough which can NOT be denorm
635	        SetToZero<oExpoWidth,MantWidth>(o_sign,o_expo,o_mant);
636	    } else if (i_expo <= kExpoBiasDelta ) { // Denorm : 1.xxx * 2^(-15) = 0.1xxx * 2^(-14)
637	        //if (DENORM == DENORM_YES) {
638	            iExpoType i_shift = kExpoBiasDelta - i_expo + 1;
639	
640	            bool overflow = FpMantDecShiftRight<MantWidth,iExpoWidth,MantWidth>(i_mant,i_shift,o_mant);
641	
642	            if (overflow) { // become a norm value: 1.0*2^1
643	                o_expo = 1;
644	            } else {
645	                o_expo = 0;
646	            }
647	        //} else {
648	        //    SetToZero<oExpoWidth,MantWidth>(o_sign,o_expo,o_mant);
649	        //}
650	    } else { // norm
651	        o_expo = i_expo - kExpoBiasDelta;
652	        o_mant = i_mant;
653	    }
654	    
655	    // NAN propagation
656	    //if (NANMODE == NAN_YES) {
657	        bool is_nan = IsNaN<iExpoWidth,MantWidth>(i_expo,i_mant);
658	        if (is_nan) {
659	            o_sign = i_sign;
660	            o_expo = koExpoMax;
661	            o_mant = i_mant;
662	        }
663	    //}
664	    
665	    return FpFloatToBits<oExpoWidth,MantWidth>(o_sign,o_expo,o_mant);
666	}
