671	//1, convert iMant -> oMant firstly, with RNE 
672	//2, convert iOxpo -> oExpo secondly
673	template<unsigned int iExpoWidth, unsigned int iMantWidth, unsigned int oExpoWidth, unsigned int oMantWidth, unsigned int DENORM, unsigned int NANMODE >
674	ACINTT(1+oExpoWidth+oMantWidth) FpWidthDec (
675	    ACINTT(1+iExpoWidth+iMantWidth) bits
676	    ) {
677	
678	    #pragma CTC SKIP
679	    assert (iMantWidth >= oMantWidth);
680	    assert (iExpoWidth >= oExpoWidth);
681	    #pragma CTC ENDSKIP
682		
683	    const unsigned int koExpoMax = (1ull << oExpoWidth) - 1 ;
684	    //const unsigned int kiExpoMax = (1ull << iExpoWidth) - 1 ;
685	    const unsigned int kiExpoBias = (1ull<< iExpoWidth)/2 - 1;
686	    const unsigned int koExpoBias = (1ull<< oExpoWidth)/2 - 1;
687	    const unsigned int kExpoBiasDelta = kiExpoBias - koExpoBias;
688	
689	    // Exmaple: original 5 bits, need keep 2 MSB bits
690	    // L: LSB; G: GUARD; S:STICK; T: TRUNC
691	    // x  x  x  x  x 
692	    //   [L][G][ S  ] 
693	    //      [   T   ]
694	    const unsigned int TruncWidth = iMantWidth-oMantWidth;
695	    const unsigned int StickWidth = iMantWidth-oMantWidth-1;
696	
697	    typedef ACINTF(1+iExpoWidth+iMantWidth) uIn;
698	    
699	    typedef ACINTF(1) SignType;
700	    
701	    typedef ACINTF(iMantWidth)      iMantType;
702	    typedef ACINTF(iMantWidth+1)    iMantPlusOneType;
703	    
704	    typedef ACINTF(oMantWidth)      oMantType;
705	    typedef ACINTF(1+oMantWidth)    oMantPlusOneType;
706	    typedef ACINTF(2+oMantWidth)    oMantPlusTwoType;
707	
708	    typedef ACINTF(iExpoWidth) iExpoType;
709	    typedef ACINTF(oExpoWidth) oExpoType;
710	
711	    typedef ACINTF(TruncWidth) TruncType;
712	    typedef ACINTF(StickWidth) StickType;
713	    typedef ACINTF(1)          GuardType;
714	    typedef ACINTF(1)          CarryType;
715	    
716	    SignType  i_sign;
717	    iExpoType i_expo;
718	    iMantType i_mant;
719	    
720	    FpSignedBitsToFloat<iExpoWidth,iMantWidth>(bits,i_sign,i_expo,i_mant);
721	
722	    SignType  o_sign = i_sign;
723	    oExpoType o_expo;
724	    oMantType o_mant;
725	
726	    bool is_inf = 0;
727	    bool is_zero = 0;
728	    // ====================
729	    if (i_expo >= koExpoMax + kExpoBiasDelta ) { // set to INF if greater than koExpoMax`
730	        is_inf = 1;
731	    } else if (i_expo < kExpoBiasDelta - oMantWidth) { // 0, small enough which can NOT be denorm
732	        is_zero = 1;
733	    } else if (i_expo <= kExpoBiasDelta ) { // Denorm : fp16: 1.xxx * 2^(-15) = 0.1xxx * 2^(-14)
734	            iExpoType i_shift = kExpoBiasDelta - i_expo + 1;
735	
736	            bool overflow = FpMantDecShiftRight<iMantWidth,iExpoWidth,oMantWidth>(i_mant,i_shift,o_mant);
737	
738	        if (DENORM == DENORM_YES) {
739	            if (overflow) { // become a norm value, and mant must be ZERO
740	                o_expo = 1;
741	            } else {
742	                o_expo = 0;
743	            }
744	        } else {
745	            if (overflow) { // become a norm value, and mant must be ZERO
746	                o_expo = 1;
747	            } else {
748	                is_zero = 1;
749	            }
750	        }
751	    } else { // norm
752	        // EXPO
753	        o_expo = i_expo - kExpoBiasDelta;
754	
755	        // MANT
756	        iMantPlusOneType i_mant_p1; i_mant_p1 = i_mant;
757	        i_mant_p1[iMantWidth] = 1; // add implied 1 on msb
758	    
759	        oMantPlusOneType o_mant_p1;
760	
761	        bool overflow= FpMantRNE<iMantWidth+1,oMantWidth+1>(i_mant_p1,o_mant_p1);
762	        o_mant = o_mant_p1; // remove the implied MSB 1
763	
764	        if (overflow) {
765	            o_expo++;
766	            if (o_expo==koExpoMax) {
767	                is_inf = 1;
768	            }
769	        }
770	    }
771	
772	    if (is_inf) {
773	        SetToInf<oExpoWidth,oMantWidth>(o_sign,o_expo,o_mant);
774	    }
775	
776	    if (DENORM == DENORM_YES) {
777	        if (is_zero) {
778	            SetToZero<oExpoWidth,oMantWidth>(o_sign,o_expo,o_mant);
779	        }
780	    } else {
781	        //if (is_zero || o_expo==0) {
782	        if (is_zero) {
783	            SetToZero<oExpoWidth,oMantWidth>(o_sign,o_expo,o_mant);
784	        }
785	    }
786	    
787	    // NAN propagation
788	    //if (NANMODE == NAN_YES) {
789	        bool is_nan = IsNaN<iExpoWidth,iMantWidth>(i_expo,i_mant);
790	        if (is_nan) {
791	            o_sign = i_sign;
792	            o_expo = koExpoMax;
793	            o_mant = i_mant;
794	        }
795	    //}
796	
797	    return FpFloatToSignedBits<oExpoWidth,oMantWidth>(o_sign,o_expo,o_mant);
798	}
