801	// FUNCTION: INTEGER to FLOAT
802	// with assumption:
803	// Fraction will not become a Denorm
804	// Fraction will not become a Inf
805	//===========================================================================
806	template<unsigned int FractionWidth, unsigned int ExpoWidth, unsigned int MantWidth >
807	ACINTF(1+ExpoWidth+MantWidth) FpFractionToFloat (
808	    ACINTF(FractionWidth) fraction
809	    ) {
810	    
811	    const unsigned int kExpoBias = (1ull<<ExpoWidth)/2 - 1;
812	    
813	    typedef ACINTF(FractionWidth) FracType;
814	    typedef ACINTF(FractionWidth+1) FracPlusOneType;
815	    
816	    typedef ACINTF(ExpoWidth) ExpoType;
817	    typedef ACINTF(MantWidth) MantType;
818	    typedef ACINTF(MantWidth+1) MantPlusOneType;
819	    typedef ACINTF(1)         SignType;
820	    
821	    SignType o_sign = 0;
822	    ExpoType o_expo = kExpoBias;
823	    MantType o_mant = 0;
824	
825	    
826	    bool is_zero = 0;
827	    if (fraction != 0) {
828	        FracType zero_count = IntLeadZero<FractionWidth>(fraction);
829	        FracType zero_count_p1 = zero_count + 1;
830	        FracPlusOneType fraction_p1 = fraction;
831	        FracPlusOneType shifted_frac_p1 = fraction_p1 << zero_count_p1;
832	
833	        #pragma CTC SKIP
834	        if (FractionWidth<=MantWidth) {
835	            FracType shifted_frac = shifted_frac_p1; // remove the MSB 1
836	            o_mant = shifted_frac<<(MantWidth - FractionWidth);
837	            o_expo -= zero_count+1;
838	        #pragma CTC ENDSKIP
839	        } else {
840	            MantPlusOneType o_mant_p1;
841	            bool overflow = FpMantRNE<FractionWidth+1,MantWidth+1>(shifted_frac_p1,o_mant_p1);
842	            if (overflow) {
843	                //if (o_expo <= zero_count) {
844	                //    is_zero = 1;
845	                //} else {
846	                    o_expo -= zero_count;
847	                    o_mant = o_mant_p1>>1;
848	                //}
849	            } else {
850	                if (o_expo <= zero_count + 1) {
851	                    is_zero = 1;
852	                } else {
853	                    o_mant = o_mant_p1;
854	                    o_expo -= zero_count + 1;
855	                }
856	            }
857	        }
858	    } else {
859	        is_zero = 1;
860	    }
861	
862	    if (is_zero) {
863	        SetToZero<ExpoWidth,MantWidth>(o_sign,o_expo,o_mant);
864	    }
865	    
866	    return FpFloatToBits<ExpoWidth,MantWidth>(o_sign,o_expo,o_mant);
867	
