947	template<unsigned int ExpoWidth, unsigned int MantWidth >
948	void FpNormalize (
949	     ACINTF(1)& sign
950	    ,ACINTF(ExpoWidth)& expo
951	    ,ACINTF(MantWidth)& mant
952	    ) {
953	
954	    typedef ACINTF(ExpoWidth) ExpoType; 
955	    typedef ACINTF(MantWidth) MantType; 
956	
957	    MantType zero_count = IntLeadZero<MantWidth>(mant);
958	
959	    if (expo <= zero_count || mant == 0) {
960	        SetToZero<ExpoWidth,MantWidth>(sign,expo,mant);
961	    } else {
962	        sign  = sign;
963	        expo -= zero_count;
964	        mant <<= zero_count;
965	    }
966	}
