970	// 1, increase the input a/b to InternalMantWidth, which should be 2*MantWIdth+2 to keep all precision
971	// 2, add the mantissa and do RNE
972	// 3, 
973	template <unsigned int ExpoWidth, unsigned int MantWidth >
974	ACINTT(1+ExpoWidth+MantWidth) FpAdd (
975	      ACINTT(1+ExpoWidth+MantWidth) a
976	     ,ACINTT(1+ExpoWidth+MantWidth) b
977	    ) {
978	    
979	    const unsigned int kExpoMax = (1ull << ExpoWidth) - 1;
980	    const unsigned int kMantMoreWidth = MantWidth+2; // No precision lost
981	    const unsigned int InternalMantWidth = kMantMoreWidth + MantWidth + 1; // No precision lost
982	    
983	    typedef ACINTT(1+ExpoWidth+MantWidth)   sT;
984	    typedef ACINTF(1+ExpoWidth+MantWidth)   uT;
985	
986	    typedef ACINTF(1)           SignType;
987	    typedef ACINTF(MantWidth)   MantType;
988	    typedef ACINTF(ExpoWidth)   ExpoType;
989	    
990	    typedef ACINTF(1+ExpoWidth) ExpoPlusOneType;
991	
992	    typedef ACINTF(1+MantWidth) MantPlusOneType; // PlusOne is to hold the implied 1
993	    typedef ACINTF(2+MantWidth) MantPlusTwoType; // PlusTwo is to check whether overflow
994	    typedef ACINTF(2*MantWidth+1) MantX2PlusOneType; 
995	    typedef ACINTF(InternalMantWidth)  InternalMantType; 
996	    typedef ACINTF(1+InternalMantWidth) InternalMantPlusOneType; 
997	
998	    typedef ACINTT(1+ExpoWidth) SignedShiftType;
999	    typedef ACINTF(ExpoWidth)   ShiftType;
1000	    
1001	    typedef SignType            oSignType;
1002	    typedef ExpoPlusOneType     oExpoType;
1003	    typedef MantType            oMantType;
1004	    
1005	    ACINTF(1)   a_sign,b_sign,o_sign;
1006	    ExpoType    a_expo,b_expo,o_expo;
1007	    MantType    a_mant,b_mant,o_mant;
1008	    
1009	    FpSignedBitsToFloat<ExpoWidth,MantWidth>(a,a_sign,a_expo,a_mant);
1010	    FpSignedBitsToFloat<ExpoWidth,MantWidth>(b,b_sign,b_expo,b_mant);
1011	
1012	    MantPlusOneType a_mant_p1 = a_mant;
1013	    //if (is_a_denorm) {
1014	    //    a_expo=1; // make it 1 to treat as norm
1015	    //    a_mant_p1[MantWidth] = 0; // add implied 0 on msb
1016	    //} else {
1017	    if (IsZero<ExpoWidth,MantWidth>(a_expo,a_mant)) {
1018	          a_mant_p1[MantWidth] = 0; // add implied 0 on msb
1019	    } else {
1020	          a_mant_p1[MantWidth] = 1; // add implied 1 on msb
1021	    }
1022	    //}
1023	
1024	    MantPlusOneType b_mant_p1 = b_mant;
1025	    if (IsZero<ExpoWidth,MantWidth>(b_expo,b_mant)) {
1026	          b_mant_p1[MantWidth] = 0; // add implied 0 on msb
1027	    } else {
1028	          b_mant_p1[MantWidth] = 1; // add implied 1 on msb
1029	    }
1030	
1031	    bool is_a_greater = (a_expo > b_expo) || (a_expo == b_expo && a_mant >= b_mant); // a_ may be less when a_expo==b_expo
1032	    o_expo = (is_a_greater) ? (a_expo) : (b_expo);
1033	
1034	    ShiftType a_right_shift = (is_a_greater) ?  (ShiftType)0 : (ShiftType)(b_expo - a_expo);
1035	    ShiftType b_right_shift = (is_a_greater) ?  (ShiftType)(a_expo - b_expo) : (ShiftType)0;
1036	    
1037	    SignedShiftType a_left_shift = kMantMoreWidth - a_right_shift;
1038	    SignedShiftType b_left_shift = kMantMoreWidth - b_right_shift;
1039	    
1040	    InternalMantType a_int_mant_p1 = ((InternalMantType)a_mant_p1) << a_left_shift;
1041	    InternalMantType b_int_mant_p1 = ((InternalMantType)b_mant_p1) << b_left_shift;
1042	    #ifdef SVDEBUG    
1043	    printf("\n a_mant  = %x",a_mant);
1044	    printf("\n b_mant  = %x",b_mant);
1045	    printf("\n a_mant_p1  = %x",a_mant_p1);
1046	    printf("\n b_mant_p1  = %x",b_mant_p1);
1047	    printf("\n a_int_mant_p1  = %x",a_int_mant_p1);
1048	    printf("\n b_int_mant_p1  = %x",b_int_mant_p1);
1049	    #endif
1050	            
1051	    bool is_addition = (a_sign == b_sign);
1052	    
1053	    // If this is wrong when a_expo==b_expo, we'll recover later on(KEY: RECOVERY).
1054	    o_sign = is_a_greater ? a_sign : b_sign;
1055	
1056	    InternalMantType addend_larger  = is_a_greater ? a_int_mant_p1 : b_int_mant_p1;
1057	    InternalMantType addend_smaller = is_a_greater ? b_int_mant_p1 : a_int_mant_p1;
1058	    
1059	    //InternalMantType int_mant;
1060	
1061	    InternalMantPlusOneType int_mant_p1;
1062	    if (is_addition) {
1063	        int_mant_p1 = (InternalMantPlusOneType)addend_larger + (InternalMantPlusOneType)addend_smaller;
1064	    } else {
1065	        int_mant_p1 = (InternalMantPlusOneType)addend_larger - (InternalMantPlusOneType)addend_smaller;
1066	    }
1067	        
1068	    #ifdef SVDEBUG    
1069	    printf("\n addend_larger  = %x",addend_larger);
1070	    printf("\n addend_smaller = %x",addend_smaller);
1071	    #endif
1072	
1073	    bool is_inf = 0;
1074	    InternalMantType int_mant;
1075	    if (int_mant_p1[InternalMantWidth]) {
1076	        if (o_expo<kExpoMax-1) {
1077	            o_expo++;
1078	            int_mant = int_mant_p1>>1;
1079	        } else {
1080	            is_inf = 1;
1081	            // set as INF
1082	            //SetToInf<ExpoWidth,MantWidth>(o_sign,o_expo,o_mant);
1083	        }
1084	        #ifdef SVDEBUG    
1085	        printf("\n p0:int_mant  = %x",int_mant);
1086	        printf("\n p0:o_expo  = %x",o_expo);
1087	        #endif
1088	    } else {
1089	        int_mant = int_mant_p1; // remove the MSB, which is 0 for sure
1090	        #ifdef SVDEBUG    
1091	        printf("\n p1:int_mant  = %x",int_mant);
1092	        printf("\n p1:o_expo  = %x",o_expo);
1093	        #endif
1094	        FpNormalize<ExpoWidth,InternalMantWidth>(o_sign,o_expo,int_mant); // make MSB of o_mant_p1 to be 1, or set mant = 0 if < norm
1095	        #ifdef SVDEBUG    
1096	        printf("\n p2:int_mant  = %x",int_mant);
1097	        printf("\n p2:o_expo  = %x",o_expo);
1098	        #endif
1099	    }
1100	
1101	    MantPlusOneType o_mant_p1;
1102	    bool overflow = FpMantRNE<InternalMantWidth,MantWidth+1>(int_mant,o_mant_p1);
1103	    #ifdef SVDEBUG    
1104	    printf("\n FpMantRNE:int_mant  = %x",int_mant);
1105	    printf("\n FpMantRNE:o_mant_p1  = %x",o_mant_p1);
1106	    printf("\n overflow  = %x",overflow);
1107	    #endif
1108	
1109	    if (overflow) {
1110	        if (o_expo<kExpoMax-1) {
1111	            o_expo++;
1112	        } else {
1113	            is_inf = 1;
1114	        }
1115	    }
1116	
1117	    o_mant = o_mant_p1; // remove implied 1 on MSB, or o_mant is 0 if in case of overflow
1118	
1119	    if (is_inf) {
1120	        SetToInf<ExpoWidth,MantWidth>(o_sign,o_expo,o_mant);
1121	    }
1122	    
1123	    // NaN pro
1124	    bool is_a_nan = IsNaN<ExpoWidth,MantWidth>(a_expo,a_mant);
1125	    bool is_b_nan = IsNaN<ExpoWidth,MantWidth>(b_expo,b_mant);
1126	
1127	    if (is_a_nan) {
1128	        o_sign = a_sign;
1129	        o_expo = a_expo;
1130	        o_mant = a_mant;
1131	    } else if (is_b_nan) {
1132	        o_sign = b_sign;
1133	        o_expo = b_expo;
1134	        o_mant = b_mant;
1135	    }
1136	
1137	    sT o = FpFloatToSignedBits<ExpoWidth,MantWidth>(o_sign,o_expo,o_mant);
1138	    return o;
1139	}
