1183	// return true if a > b
1184	// return false if a <= b
1185	template <unsigned int ExpoWidth, unsigned int MantWidth, bool MAX >
1186	ACINTT(1+ExpoWidth+MantWidth) FpCmp (
1187	     ACINTT(1+ExpoWidth+MantWidth) a
1188	    ,ACINTT(1+ExpoWidth+MantWidth) b
1189	    ) {
1190	
1191	    typedef ACINTF(1)           SignType;
1192	    typedef ACINTF(ExpoWidth)   ExpoType;
1193	    typedef ACINTF(MantWidth)   MantType;
1194	    typedef ACINTT(1+ExpoWidth+MantWidth)   oType;
1195	
1196	    SignType a_sign,b_sign;
1197	    ExpoType a_expo,b_expo;
1198	    MantType a_mant,b_mant;
1199	    
1200	    FpSignedBitsToFloat<ExpoWidth,MantWidth>(a,a_sign,a_expo,a_mant);
1201	    FpSignedBitsToFloat<ExpoWidth,MantWidth>(b,b_sign,b_expo,b_mant);
1202	    
1203	    bool is_abs_a_greater = true;
1204	    if (a_expo > b_expo) {
1205	        is_abs_a_greater = true;
1206	    } else if (a_expo < b_expo) {
1207	        is_abs_a_greater = false;
1208	    } else {
1209	        if (a_mant > b_mant) {
1210	            is_abs_a_greater = true;
1211	        } else {
1212	            is_abs_a_greater = false;
1213	        }
1214	    }
1215	
1216	    bool is_a_postive = (a_sign==0);
1217	    bool is_b_postive = (b_sign==0);
1218	    bool is_a_greater;
1219	
1220	    if (is_a_postive) {
1221	        if (is_b_postive) {
1222	            is_a_greater = is_abs_a_greater ? true : false;
1223	        } else {
1224	            is_a_greater = true;
1225	        }
1226	    } else {
1227	        if (is_b_postive) {
1228	            is_a_greater = false;
1229	        } else {
1230	            is_a_greater = is_abs_a_greater ? false : true;
1231	        }
1232	    }
1233	
1234	    oType o;
1235	    if (MAX==true) {
1236	        o = is_a_greater ? a : b;
1237	    } else {
1238	        o = is_a_greater ? b : a;
1239	    }
1240	    
1241	    bool is_a_nan = IsNaN<ExpoWidth,MantWidth>(a_expo,a_mant);
1242	    bool is_b_nan = IsNaN<ExpoWidth,MantWidth>(b_expo,b_mant);
1243	
1244	    if (is_a_nan) {
1245	        o = a;
1246	    } else if (is_b_nan) {
1247	        o = b;
1248	    }
1249	
1250	    return o;
1251	}
