1280	// o = a * b
1281	// a*b ->(full width) m -(narrow expo.width)-> n -(narrow mant.width)-> o
1282	template <unsigned int ExpoWidth, unsigned int MantWidth >
1283	ACINTT(1+ExpoWidth+MantWidth) FpMul (
1284	      ACINTT(1+ExpoWidth+MantWidth) a
1285	     ,ACINTT(1+ExpoWidth+MantWidth) b
1286	    ) {
1287	
1288	    const unsigned int pMantWidth = 2 * MantWidth + 1;
1289	    const unsigned int pExpoWidth = ExpoWidth;
1290	    const unsigned int kExpoBias = (1ull<<ExpoWidth)/2 - 1;
1291	    
1292	    const unsigned int pExpoMax = (1ull << pExpoWidth) - 1;
1293	
1294	    typedef ACINTF(1)               SignType;
1295	    typedef ACINTF(ExpoWidth)       ExpoType;
1296	    typedef ACINTF(MantWidth)       MantType;
1297	    typedef ACINTF(1+MantWidth)     MantPlusOneType;
1298	    
1299	    typedef ACINTF(pExpoWidth)      pExpoType;
1300	    typedef ACINTT(pExpoWidth+2)    pSignedExpoPlusOneType;
1301	    typedef ACINTF(pMantWidth)      pMantType;
1302	    typedef ACINTF(pMantWidth+1)    pMantPlusOneType;
1303	    
1304	    typedef ACINTT(1+ExpoWidth+MantWidth)   sT;
1305	    typedef ACINTT(1+pExpoWidth+pMantWidth) pT;
1306	    
1307	    typedef ACINTF(1+ExpoWidth+MantWidth)   uT;
1308	
1309	    // p is the product p = a * b
1310	
1311	    SignType a_sign,b_sign,o_sign;
1312	    ExpoType a_expo,b_expo,o_expo;
1313	    MantType a_mant,b_mant,o_mant;
1314	    
1315	    SignType  p_sign;
1316	    pExpoType p_expo;
1317	    pMantType p_mant;
1318	
1319	    uT ua = (uT)a;
1320	    uT ub = (uT)b;
1321	    
1322	    FpBitsToFloat<ExpoWidth,MantWidth>(ua,a_sign,a_expo,a_mant);
1323	    FpBitsToFloat<ExpoWidth,MantWidth>(ub,b_sign,b_expo,b_mant);
1324	
1325	    bool is_a_zero = IsZero<ExpoWidth,MantWidth>(a_expo,a_mant);
1326	    bool is_b_zero = IsZero<ExpoWidth,MantWidth>(b_expo,b_mant);
1327	
1328	    // + implied 1
1329	    MantPlusOneType a_mant_p1; a_mant_p1=a_mant;
1330	    if (is_a_zero) {
1331	        a_mant_p1[MantWidth] = 0; // add implied 0 on msb
1332	    } else {
1333	        a_mant_p1[MantWidth] = 1; // add implied 1 on msb
1334	    }
1335	
1336	    MantPlusOneType b_mant_p1; b_mant_p1=b_mant;
1337	    if (is_b_zero) {
1338	        b_mant_p1[MantWidth] = 0; // add implied 0 on msb
1339	    } else {
1340	        b_mant_p1[MantWidth] = 1; // add implied 1 on msb
1341	    }
1342	
1343	    pMantPlusOneType p_mant_p1 = a_mant_p1 * b_mant_p1;
1344	    
1345	    // sign
1346	    p_sign = a_sign ^ b_sign;
1347	
1348	    // expo
1349	    bool is_inf = 0;
1350	    bool is_zero = 0;
1351	    if (is_a_zero || is_b_zero || a_expo + b_expo < kExpoBias ) {
1352	        is_zero = 1;
1353	    } else if (a_expo + b_expo >= pExpoMax + kExpoBias) {
1354	        //SetToInf<pExpoWidth,pMantWidth>(p_sign,p_expo,p_mant);
1355	        is_inf = 1;
1356	    } else {
1357	        p_expo = a_expo + b_expo - kExpoBias;
1358	
1359	        // normalize and then remove the MSB 1 to make it implied
1360	        if (p_mant_p1[pMantWidth]) {
1361	            if (p_expo<pExpoMax-1) {
1362	                p_expo++;
1363	                p_mant = p_mant_p1;
1364	            } else {
1365	                is_inf = 1;
1366	            }
1367	        } else {
1368	            p_mant = p_mant_p1<<1; // shift 0 from LSB, and remove 2bits from MSB
1369	        }
1370	    }
1371	    
1372	    // Convert to uBits
1373	    pT p  = FpFloatToSignedBits<pExpoWidth,pMantWidth>(p_sign,p_expo,p_mant);
1374	
1375	    //uT uo = FpWidthDec<pExpoWidth,pMantWidth,ExpoWidth,MantWidth,DENORM_NO,NAN_NO>(p);
1376	    uT uo = FpMantWidthDec<ExpoWidth,pMantWidth,MantWidth,DENORM_NO,NAN_NO>(p);
1377	    FpBitsToFloat<ExpoWidth,MantWidth>(uo,o_sign,o_expo,o_mant);
1378	
1379	    // set to inf
1380	    if (is_inf) {
1381	        SetToInf<ExpoWidth,MantWidth>(o_sign,o_expo,o_mant);
1382	    } 
1383	    
1384	    // set to zero
1385	    if (is_zero || o_expo==0) {
1386	        SetToZero<ExpoWidth,MantWidth>(o_sign,o_expo,o_mant);
1387	    }
1388	    
1389	    // for NaN propogation
1390	    bool is_a_nan = IsNaN<ExpoWidth,MantWidth>(a_expo,a_mant);
1391	    bool is_b_nan = IsNaN<ExpoWidth,MantWidth>(b_expo,b_mant);
1392	    if (is_a_nan) {
1393	        o_sign = a_sign;
1394	        o_expo = a_expo;
1395	        o_mant = a_mant;
1396	    } else if (is_b_nan) {
1397	        o_sign = b_sign;
1398	        o_expo = b_expo;
1399	        o_mant = b_mant;
1400	    }
1401	    
1402	    sT o  = FpFloatToSignedBits<ExpoWidth,MantWidth>(o_sign,o_expo,o_mant);
1403	
1404	    return o;
1405	}
