1418	    typedef ACINTF(ExpoWidth) ExpoType;
1419	    typedef ACINTF(MantWidth) MantType;
1420	
1421	    SignType i_sign,o_sign;
1422	    ExpoType i_expo,o_expo;
1423	    MantType i_mant,o_mant;
1424	    
1425	    FpSignedBitsToFloat<ExpoWidth,MantWidth>(i,i_sign,i_expo,i_mant);
1426	
1427	    bool is_nan = IsNaN<ExpoWidth,MantWidth>(i_expo,i_mant);
1428	    if (is_nan || i_sign==0) {
1429	        o_sign = i_sign;
1430	        o_expo = i_expo;
1431	        o_mant = i_mant;
1432	    } else {
1433	        o_sign = (SignType)0;
1434	        o_expo = (ExpoType)0;
1435	        o_mant = (MantType)0;
