1442	template <unsigned int IntWidth, unsigned int ExpoWidth, unsigned int MantWidth >
1443	ACINTT(1+ExpoWidth+MantWidth) FpIntToFloat (
1444	      ACINTT(IntWidth) i
1445	    ) {
1446	    //const unsigned int kDropBits = IntWidth - 2 - MantWidth;
1447	    const unsigned int kExpoBias = (1ull<<ExpoWidth)/2 - 1;
1448	    const unsigned int kExpoMax = (1ull << ExpoWidth) - 1;
1449	
1450	    typedef ACINTF(1)         SignType;
1451	    typedef ACINTF(ExpoWidth) ExpoType;
1452	    typedef ACINTF(MantWidth) MantType;
1453	    typedef ACINTF(MantWidth+1) MantPlusOneType;
1454	
1455	    typedef ACINTF(IntWidth)   iTypeF;
1456	    typedef ACINTT(IntWidth)   iType;
1457	
1458	    SignType o_sign;
1459	    ExpoType o_expo;
1460	    MantType o_mant;
1461	    MantPlusOneType o_mant_p1;
1462	
1463	    bool is_inf = false;
1464	
1465	    o_sign  = i.template slc<1>(IntWidth-1);
1466	    iType i_value = i;
1467	    if (i == 0) {
1468	        SetToZero<ExpoWidth,MantWidth>(o_sign,o_expo,o_mant);
1469	    } else {
1470	        iTypeF  i_abs;
1471	        if (o_sign) { // negtive
1472	            //i_abs = ~i_value; // NOTE: in HLS ~ means invert(A) + 1, but in VCS it is invert(A), or use (0-i_value) to get complement
1473	            i_abs = -i_value;
1474	        } else { // postive
1475	            i_abs = i_value;
1476	        }
1477	
1478	        iTypeF lead_zero_count = IntLeadZero<IntWidth>(i_abs);
1479	        iTypeF int_mant = i_abs << lead_zero_count;
1480	
1481	        o_expo = IntWidth - 1 - lead_zero_count + kExpoBias;
1482	        // below shift should be replaced by RNE
1483	        bool overflow = FpMantRNE<IntWidth,MantWidth+1>(int_mant,o_mant_p1);
1484	        if (o_expo == kExpoMax) {
1485	                is_inf = 1;
1486	        } else if (overflow) {
1487	            if (o_expo < kExpoMax-1) {
1488	                o_expo++; // o_mant_p1 must be 0;
1489	            } else {
1490	                is_inf = 1;
1491	            }
1492	        }
1493	        // remove MSB
1494	        o_mant = o_mant_p1; // remove MSB
1495	        // remove MSB done
1496	
1497	    }
1498	
1499	    if (is_inf) {
1500	        SetToInf<ExpoWidth,MantWidth>(o_sign,o_expo,o_mant);
1501	    }
1502	    
1503	    return FpFloatToSignedBits<ExpoWidth,MantWidth>(o_sign,o_expo,o_mant);
1504	}
