1508	ACINTT(IntWidth) FpFloatToInt (
1509	      ACINTT(1+ExpoWidth+MantWidth) bits
1510	    ) {
1511	    const long int kExpoBias = (1ull<<ExpoWidth)/2 - 1;
1512	    const long int internalSize = kExpoBias+1+MantWidth;
1513	
1514	    typedef ACINTT(IntWidth)   intType;
1515	    typedef ACINTF(1)         SignType;
1516	    typedef ACINTF(ExpoWidth) ExpoType;
1517	    typedef ACINTT(ExpoWidth+1) SignedExpoType;
1518	    typedef ACINTF(MantWidth) MantType;
1519	    typedef ACINTF(MantWidth+1) MantPlusOneType;
1520	    typedef ACINTF(MantWidth+2) MantPlusTwoType;
1521	
1522	    typedef ACINTF(internalSize) internalType;
1523	    
1524	    intType oIntMax =  (1ull<<(IntWidth-1)) - 1;
1525	    intType oIntMin = -(1ull<<(IntWidth-1));
1526	    //ExpoType kExpoBias = (1ull<<(ExpoWidth-1)) - 1;
1527	    
1528	    SignType i_sign;
1529	    ExpoType i_expo;
1530	    MantType i_mant;
1531	    FpSignedBitsToFloat<ExpoWidth,MantWidth>(bits,i_sign,i_expo,i_mant);
1532	
1533	    MantPlusOneType i_mant_p1; i_mant_p1=i_mant;
1534	    i_mant_p1[MantWidth] = 1;
1535	
1536	    MantPlusTwoType i_mant_p2 = i_mant_p1;
1537	
1538	    SignedExpoType shift = MantWidth - (i_expo - kExpoBias);
1539	    //internalType internal_int = ((internalType)(i_mant_p1)) >> shift;
1540	    internalType internal_int = IntSignedShiftRight<MantWidth+2,ExpoWidth+1,internalSize>(i_mant_p2,shift);
1541	
1542	    intType o_int;
1543	    if (internal_int > oIntMax) {
1544	        o_int = i_sign ? oIntMin : oIntMax;
1545	    } else {
1546	        if (i_sign) {
1547	            o_int = -internal_int;
1548	        } else {
1549	            o_int = internal_int;
1550	        }
1551	    }
1552	
1553	    // for NaN propogation: set to MAX
1554	    bool is_nan = IsNaN<ExpoWidth,MantWidth>(i_expo,i_mant);
1555	    if (is_nan) {
1556	        o_int = oIntMin;
1557	    }
1558	
1559	    return o_int;
1560	}
