1563	template <unsigned int ExpoWidth, unsigned int MantWidth, unsigned int SftWidth, unsigned int IntWidth, unsigned int FraWidth >
1564	void FpFloatToIntFrac (
1565	      ACINTT(1+ExpoWidth+MantWidth) i_float
1566	     ,ACINTT(SftWidth)& i_rshift
1567	     ,ACINTF(IntWidth)& o_int
1568	     ,ACINTF(FraWidth)& o_fra
1569	    ) {
1570	    const unsigned int kExpoBias = (1ull<<ExpoWidth)/2 - 1;
1571	    const unsigned int kExpoMax = (1ull<<ExpoWidth)/2;
1572	    const unsigned int kSftMax = (1ull<<SftWidth)/2;
1573	    const unsigned int kMax = kExpoMax + kSftMax;
1574	
1575	
1576	    typedef ACINTF(IntWidth)  intType;
1577	    typedef ACINTF(FraWidth)  fraType;
1578	
1579	    intType intMax = (1ull<<IntWidth) - 1;
1580	
1581	    typedef ACINTF(1)         SignType;
1582	
1583	    typedef ACINTF(ExpoWidth)   ExpoType;
1584	    typedef ACINTT(ExpoWidth)   SignedExpoType;
1585	    typedef ACINTT(ExpoWidth+2) SignedExpoPlusTwoType;
1586	
1587	    typedef ACINTF(MantWidth)   MantType;
1588	    typedef ACINTF(MantWidth+1) MantPlusOneType;
1589	    
1590	    typedef ACINTT(SftWidth) SftType;
1591	    typedef ACINTF(kMax) maxType;
1592	    
1593	    SignType i_sign;
1594	    ExpoType i_expo;
1595	    MantType i_mant;
1596	    FpSignedBitsToFloat<ExpoWidth,MantWidth>(i_float,i_sign,i_expo,i_mant);
1597	
1598	    MantPlusOneType i_mant_p1; i_mant_p1=i_mant;
1599	    //if (IsZero<ExpoWidth,MantWidth>(i_expo,i_mant)) {
1600	    //    i_mant_p1[MantWidth] = 0;
1601	    //} else {
1602	        i_mant_p1[MantWidth] = 1;
1603	    //}
1604	
1605	    SignedExpoType abs_expo = (i_expo - kExpoBias);
1606	    SignedExpoPlusTwoType lshift = (abs_expo - i_rshift) - MantWidth;
1607	
1608	    maxType m_int = (maxType)(i_mant_p1) << lshift;
1609	
1610	    if (lshift >= 0) {
1611	        o_fra = 0;
1612	    } else {
1613	        o_fra = (fraType)(i_mant_p1) << (FraWidth + lshift);
1614	    }
1615	
1616	    if (m_int > intMax) {
1617	        o_int = intMax;
1618	    } else {
1619	        o_int = m_int;
1620	    }
1621	
1622	    // for NaN propogation: UINT is 0
1623	    #pragma CTC SKIP
1624	    bool is_nan = IsNaN<ExpoWidth,MantWidth>(i_expo,i_mant);
1625	    if (is_nan) {
1626	        o_int = 0;
1627	        o_fra = 0;
1628	    }
1629	    #pragma CTC ENDSKIP
1630	}
