template <unsigned int ExpoWidth, unsigned int MantWidth >
ACINTT(1+ExpoWidth+MantWidth) FpMax (
      ACINTT(1+ExpoWidth+MantWidth) a
     ,ACINTT(1+ExpoWidth+MantWidth) b
